    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "inspection_progress": 0.15,
      "battery_level": 85,
      "agent_location": "Hangar_Zone_A"
    }
  },
  "fetch_maintenance_records": {
    "description": "Retrieves all digital and digitized 'dirty fingerprint' records for a specific component serial number, including technical logs and release certificates.",
    "parameters": {
      "type": "object",
      "properties": {
        "serial_number": {
          "type": "string",
          "description": "The unique serial number of the aircraft component."
        }
      },
      "required": [
        "serial_number"
      ]
    },
    "example_output": {
      "records_found": 12,
      "document_manifest": [
        "Form_8130_3",
        "Logbook_2022",
        "NIS_Statement"
      ]
    }
  },
  "reconcile_cycle_counts": {
    "description": "Performs a mathematical audit comparing the cycles recorded in technical logs against those on authorized release certificates (e.g., FAA 8130-3 or EASA Form 1).",
    "parameters": {
      "type": "object",
      "properties": {
        "serial_number": {
          "type": "string",
          "description": "The component serial number."
        }
      },
      "required": [
        "serial_number"
      ]
    },
    "example_output": {
      "total_cycles_consumed": 14200,
      "discrepancy_detected": false,
      "remaining_cycles": 5800
    }
  },
  "audit_traceability_chain": {
    "description": "Verifies the full back-to-birth chain of ownership and checks for the presence of Non-Incident Statements (NIS) for every transfer of the component.",
    "parameters": {
      "type": "object",
      "properties": {
        "serial_number": {
          "type": "string",
          "description": "The component serial number."
        }
      },
      "required": [
        "serial_number"
      ]
    },
    "example_output": {
      "chain_complete": true,
      "missing_documents": [],
      "gap_intervals": []
    }
  },
  "execute_regulatory_resolution": {
    "description": "Follows regulatory protocols to resolve gaps in documentation or cycle discrepancies. This is used when the audit finds missing information.",
    "parameters": {
      "type": "object",
      "properties": {
        "serial_number": {
          "type": "string",
          "description": "The component serial number."
        },
        "gap_type": {
          "type": "string",
          "enum": [
            "missing_nis",
            "cycle_discrepancy",
            "ownership_gap"
          ],
          "description": "The type of trace gap identified."
        }
      },
      "required": [
        "serial_number",
        "gap_type"
      ]
    },
    "example_output": {
      "resolution_status": "pending_verification",
      "action_taken": "Contacted previous operator for NIS."
    }
  },
  "update_component_status": {
    "description": "Finalizes the component status in the maintenance system as either 'CLEARED' for reinstallation or 'REJECTED'.",
    "parameters": {
      "type": "object",
      "properties": {
        "serial_number": {
          "type": "string",
          "description": "The component serial number."
        },
        "status": {
          "type": "string",
          "enum": [
            "CLEARED",
            "REJECTED"
          ],
          "description": "The final airworthiness decision."
        },
        "remarks": {
          "type": "string",
          "description": "Supporting details for the decision."
        }
      },
      "required": [
        "serial_number",
        "status",
        "remarks"
      ]
    },
    "example_output": {
      "system_updated": true,
      "transaction_id": "TXN_9988_FINAL"
    }
  }
}
